using LumiBeauty.Api.Data;using LumiBeauty.Api.DTOs;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace LumiBeauty.Api.Controllers;[ApiController][Route("api/business-settings")]public class BusinessSettingsController:ControllerBase{private readonly AppDbContext _db;public BusinessSettingsController(AppDbContext db){_db=db;}[HttpGet]public async Task<IActionResult> Get()=>Ok(await _db.BusinessSettings.AsNoTracking().FirstAsync(x=>x.Id==1));[Authorize(Roles="Admin")][HttpPut]public async Task<IActionResult> Put(UpdateBusinessSettingsRequest r){if(r.OpeningTime>r.LastAppointmentTime)return BadRequest("Açılış saati son randevu saatinden sonra olamaz.");if(r.SlotIntervalMinutes<15||r.SlotIntervalMinutes>240)return BadRequest("Aralık geçersiz.");var s=await _db.BusinessSettings.FirstAsync(x=>x.Id==1);s.OpeningTime=r.OpeningTime;s.LastAppointmentTime=r.LastAppointmentTime;s.SlotIntervalMinutes=r.SlotIntervalMinutes;await _db.SaveChangesAsync();return Ok(s);}}
